mapper.select:
SELECT COUNT(*) FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO

  W.USEYN = 1
  AND W.ORDSTATE != 'DONE'
  AND W.ORDDATE >= #{start_date}
  AND W.ORDDATE <= #{end_date}
  AND W.SHIFT = #{shift}
  AND W.ORDSTATE = #{ord_state}
  AND W.LINECD = #{line_cd}
  AND W.PROCESSCD = #{process_cd}
  AND W.WORKORDNO LIKE #{workord_no}
  AND (W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

SELECT W.SHIFT, W.WORKORDNO, W.LINECD, W.PROCESSCD,
       W.PARTNO AS PROC_PARTNO, G.PARTNM AS PROC_PARTNM, G.STANDARD AS PROC_STANDARD,
       W.ORDpriority, W.ORDQTY, G.UNIT, W.ORDSTATE,
       W.PARTNO, G.PARTNM, '' AS LOTNO, W.REMARK
FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO

  W.USEYN = 1
  AND W.ORDSTATE != 'DONE'
  AND W.ORDDATE >= #{start_date}
  AND W.ORDDATE <= #{end_date}
  AND W.SHIFT = #{shift}
  AND W.ORDSTATE = #{ord_state}
  AND W.LINECD = #{line_cd}
  AND W.PROCESSCD = #{process_cd}
  AND W.WORKORDNO LIKE #{workord_no}
  AND (W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

ORDER BY W.ORDDATE DESC, W.ORDpriority
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

